local function s2(hD,dG)if typeof(hD)~=typeof(dG)then local oq=("{1} is of type %s, but {2} is of type %s"):format(typeof(hD),typeof(dG))return false,oq end;if typeof(hD)=="table"then local s3={}for ej,d3 in pairs(hD)do s3[ej]=true;local nr,s4=s2(d3,dG[ej])if not nr then local oq=s4:gsub("{1}",("{1}[%s]"):format(tostring(ej))):gsub("{2}",("{2}[%s]"):format(tostring(ej)))return false,oq
